inline const char *ui_language_value(AirDot::UiLanguage language) {
  switch (language) {
    case AirDot::UiLanguage::EN:
      return "en";
    case AirDot::UiLanguage::DE:
      return "de";
    case AirDot::UiLanguage::NL:
      return "nl";
    case AirDot::UiLanguage::FR:
      return "fr";
    case AirDot::UiLanguage::HU:
      return "hu";
    case AirDot::UiLanguage::CS:
      return "cs";
    default:
      return "en";
  }
}

inline const char *ui_language_label(AirDot::UiLanguage language) {
  switch (language) {
    case UiLanguage::EN:
      return "English";
    case UiLanguage::DE:
      return "Deutsch";
    case UiLanguage::NL:
      return "Nederlands";
    case UiLanguage::FR:
      return "Français";
    case UiLanguage::HU:
      return "Magyar";
    case UiLanguage::CS:
      return "Čeština";
    default:
      return "English";
  }
}

inline uint8_t ui_language_count() { return 6; }

inline AirDot::UiLanguage ui_language_at(uint8_t index) {
  switch (index) {
    case 0:
      return AirDot::UiLanguage::EN;
    case 1:
      return AirDot::UiLanguage::DE;
    case 2:
      return AirDot::UiLanguage::NL;
    case 3:
      return AirDot::UiLanguage::FR;
    case 4:
      return AirDot::UiLanguage::HU;
    case 5:
      return AirDot::UiLanguage::CS;
    default:
      return AirDot::UiLanguage::EN;
  }
}

inline AirDot::UiLanguage ui_language_from_value(const std::string &value) {
  if (value == "en")
    return AirDot::UiLanguage::EN;
  if (value == "de")
    return AirDot::UiLanguage::DE;
  if (value == "nl")
    return AirDot::UiLanguage::NL;
  if (value == "fr")
    return AirDot::UiLanguage::FR;
  if (value == "hu")
    return AirDot::UiLanguage::HU;
  if (value == "cs")
    return AirDot::UiLanguage::CS;
  return AirDot::UiLanguage::EN;
}

